const fs = require('fs');
const path = require('path');
const filesSection = $json.stdout.split('---FILES---')[1] || '';
const files = filesSection.split('\n').map(f => f.trim()).filter(f => f.endsWith('.json') && f !== 'package.json');
const loaded = [];
for (const rel of files) {
  try {
    const abs = path.join('/home/orologas/n8n-workflows', rel);
    const content = fs.readFileSync(abs, 'utf8');
    const wf = JSON.parse(content);
    if (wf && wf.nodes && Array.isArray(wf.nodes)) {
      loaded.push({ relativePath: rel, name: wf.name || rel, workflow: wf });
    }
  } catch (e) {
    loaded.push({ relativePath: rel, error: String(e) });
  }
}
return [{ json: { count: loaded.length, workflows: loaded } }];

const TOKEN = $env.N8N_API_TOKEN;
const BASE = 'http://127.0.0.1:5678/api/v1';
const existing = await fetch(`${BASE}/workflows`, { headers: { 'X-N8N-API-KEY': TOKEN } }).then(r => r.json());
const existingByName = {};
for (const w of (existing.data || [])) existingByName[w.name] = w;

const results = [];
for (const item of $input.all()) {
  const wf = item.json.workflow;
  if (!wf) { results.push({ json: { name: item.json.relativePath, status: 'skipped', reason: item.json.error || 'no workflow object' } }); continue; }
  const payload = { name: wf.name, nodes: wf.nodes, connections: wf.connections, settings: wf.settings, active: false };
  const existingWf = existingByName[wf.name];
  let res;
  if (existingWf) {
    res = await fetch(`${BASE}/workflows/${existingWf.id}`, {
      method: 'PUT',
      headers: { 'X-N8N-API-KEY': TOKEN, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
  } else {
    res = await fetch(`${BASE}/workflows`, {
      method: 'POST',
      headers: { 'X-N8N-API-KEY': TOKEN, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
  }
  const ok = res.ok;
  results.push({ json: { name: wf.name, status: ok ? (existingWf ? 'updated' : 'created') : 'failed', http: res.status } });
}
return results;
